async function pollRealBackendData() {
  try {
    const res = await fetch(`${BACKEND_URL}/api/agent/stats`);
    if (res.ok) {
      const data = await res.json();
      liveBackendStats = data;
      isBackendConnected = true;
    }
  } catch (e) {
    isBackendConnected = false;
  }
}

