async function syncStateWithBackend() {
  try {
    await fetch(`${BACKEND_URL}/api/taskpilot/sync-state`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        completedTaskIds,
        workingTaskIds,
        taskTimeLogs,
        managerActivityFeed,
        managerTaskPosts,
        engineerPortalPosts,
        addedTasks,
        reassignedTaskOwners
      })
    });
  } catch (err) {
    console.error("Failed to sync state with backend:", err);
  }
}

// ─── Real-time State Sync from Backend ───────────────────────────────────────
let stateSyncInterval = null;
let lastSyncedStateHash = "";

async function startRealTimeSync() {
  // Stop existing interval if any
  if (stateSyncInterval) {
    clearInterval(stateSyncInterval);
  }

  // Sync state from backend every 3 seconds
  stateSyncInterval = setInterval(async () => {
    try {
      const resp = await fetch(`${BACKEND_URL}/api/taskpilot/state`);
      if (resp.ok) {
        const backendState = await resp.json();
        if (backendState.success) {
          // Compare with last state hash to avoid unnecessary re-renders causing screen flickering
          const stateHash = JSON.stringify({
            completedTaskIds: backendState.completedTaskIds,
            workingTaskIds: backendState.workingTaskIds,
            managerTaskPosts: backendState.managerTaskPosts,
            engineerPortalPosts: backendState.engineerPortalPosts,
            reassignedTaskOwners: backendState.reassignedTaskOwners
          });
          if (stateHash === lastSyncedStateHash) {
            return; // No changes — skip re-render to prevent UI flickering!
          }
          lastSyncedStateHash = stateHash;

          // Update local state with backend state
          completedTaskIds = backendState.completedTaskIds || completedTaskIds;
          workingTaskIds = backendState.workingTaskIds || workingTaskIds;
          taskTimeLogs = backendState.taskTimeLogs || taskTimeLogs;
          managerActivityFeed = backendState.managerActivityFeed || managerActivityFeed;
          managerTaskPosts = backendState.managerTaskPosts || managerTaskPosts;
          engineerPortalPosts = backendState.engineerPortalPosts || engineerPortalPosts;
          addedTasks = backendState.addedTasks || addedTasks;
          reassignedTaskOwners = backendState.reassignedTaskOwners || reassignedTaskOwners;

          // Apply reassignments to sources
          if (reassignedTaskOwners && Object.keys(reassignedTaskOwners).length > 0) {
            sources.forEach(source => {
              source.items.forEach(item => {
                if (reassignedTaskOwners[item.id]) {
                  item.owner = reassignedTaskOwners[item.id];
                }
              });
            });

            // Rebuild state and today queue with new assignments
            state = buildState(sources, calendarBlocks);
            const engineerName = activeProfile === "manager" ? "Manager" : (settingsProfile?.name || "Utkarsh");
            todayQueue = buildTodayCapacityQueue(state.prioritized, engineerName, taskTimeLogs);
            todayQueueGeminiScored = false;
          }

          // Re-render UI safely only when data has actually changed
          safeRender();
        }
      }
    } catch (err) {
      // Silently fail - backend might not be ready yet
      console.debug("State sync skipped:", err.message);
    }
  }, 3000);
}

// ─── Presence Heartbeat — push status to backend every 5 seconds ─────────────
let presenceAllUsers = {}; // cached from backend: { [name]: { status, lastSeen, role } }

async function pushPresenceHeartbeat() {
  const name = settingsProfile?.name || authSession?.name || "Engineer";
  const role = activeProfile;
  const email = getUserEmail();

  // Auto-compute status based on activity
  const idleSince = Date.now() - lastActivityTime;
  let status;
  if (idleSince > 5 * 60 * 1000) {
    // Idle for >5 min
    status = "idle";
  } else if (workingTaskIds.length > 0) {
    status = "dnd";
  } else {
    const presenceKey = activeProfile === "manager" ? "taskpilot:managerPresence" : "taskpilot:engineerPresence";
    status = localStorage.getItem(presenceKey) || "online";
  }

  // Update local var
  if (activeProfile === "manager") {
    managerPresenceStatus = status;
  } else {
    engineerPresenceStatus = status;
  }
  localStorage.setItem(activeProfile === "manager" ? "taskpilot:managerPresence" : "taskpilot:engineerPresence", status);
  localStorage.setItem(activeProfile === "manager" ? "taskpilot:managerLastActive" : "taskpilot:engineerLastActive", new Date().toISOString());

  try {
    await fetch(`${BACKEND_URL}/api/presence/heartbeat`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name, status, role, email })
    });

    // Also fetch all presence data so manager can see everyone
    const resp = await fetch(`${BACKEND_URL}/api/presence/all`);
    if (resp.ok) {
      const data = await resp.json();
      presenceAllUsers = data.presence || {};
    }
  } catch {
    // Backend offline — ignore silently
  }
}

function startPresenceHeartbeat() {
  if (presenceHeartbeatInterval) clearInterval(presenceHeartbeatInterval);
  pushPresenceHeartbeat(); // immediate first push
  presenceHeartbeatInterval = setInterval(pushPresenceHeartbeat, 5000);
}

function stopRealTimeSync() {
  if (stateSyncInterval) {
    clearInterval(stateSyncInterval);
    stateSyncInterval = null;
  }
}

// Register offline on page unload
window.addEventListener("beforeunload", () => {
  const name = settingsProfile?.name || authSession?.name || "Engineer";
  navigator.sendBeacon(`${BACKEND_URL}/api/presence/offline`, JSON.stringify({ name }));
});

function formatLastSeen(isoStr) {
  if (!isoStr) return "Never";
  const diff = Math.floor((Date.now() - new Date(isoStr)) / 1000);
  if (diff < 10) return "Just now";
  if (diff < 60) return `${diff}s ago`;
  if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
  if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
  return new Date(isoStr).toLocaleDateString();
}


