// ─── Presence Helper Functions ───────────────────────────────────────────────
// Deterministic fake last-seen offsets for demo engineers who have no real presence data.
// Each name maps to a fixed offset so the times are stable across re-renders.
const DEMO_PRESENCE_OFFSETS = {
  "Karan": { statusIdx: 1, minutesAgo: 7 },   // idle, 7 min ago
  "Arjun": { statusIdx: 2, minutesAgo: 23 },   // offline, 23 min ago
  "Vikram": { statusIdx: 1, minutesAgo: 42 },   // idle, 42 min ago
  "Riya": { statusIdx: 0, minutesAgo: 3 },   // online, 3 min ago
  "Aisha": { statusIdx: 2, minutesAgo: 68 },   // offline, 1h 8m ago
  "Rohan": { statusIdx: 1, minutesAgo: 15 },   // idle, 15 min ago
  "Neha": { statusIdx: 2, minutesAgo: 94 },   // offline, 1h 34m ago
  "Dev": { statusIdx: 0, minutesAgo: 1 },   // online, 1 min ago
};
const DEMO_STATUS_BY_IDX = ["online", "idle", "offline"];

function getPresenceForUser(name) {
  // Check backend presence store first (real-time)
  if (name && presenceAllUsers[name]) {
    const p = presenceAllUsers[name];
    const diffMs = Date.now() - new Date(p.lastSeen);
    // If last heartbeat > 15s ago, treat as offline
    if (diffMs > 15000 && p.status !== "offline") {
      return { status: "offline", lastSeen: p.lastSeen };
    }
    return { status: p.status, lastSeen: p.lastSeen };
  }

  // Utkarsh (the logged-in user) — use real localStorage activity
  const myName = settingsProfile?.name || authSession?.name || "Utkarsh";
  if (!name || name === myName) {
    const lastActiveStr = localStorage.getItem("taskpilot:engineerLastActive");
    if (!lastActiveStr) return { status: "offline", lastSeen: null };
    const diffMs = Date.now() - new Date(lastActiveStr);
    if (diffMs > 15000) return { status: "offline", lastSeen: lastActiveStr };
    return { status: localStorage.getItem("taskpilot:engineerPresence") || "online", lastSeen: lastActiveStr };
  }

  // Other demo engineers — return deterministic fake presence so times differ per person
  const demo = DEMO_PRESENCE_OFFSETS[name];
  if (demo) {
    const fakeLastSeen = new Date(Date.now() - demo.minutesAgo * 60 * 1000).toISOString();
    const fakeStatus = DEMO_STATUS_BY_IDX[demo.statusIdx];
    return { status: fakeStatus, lastSeen: fakeLastSeen };
  }

  // Unknown engineer — derive a stable offset from the name's char codes
  const seed = name.split("").reduce((acc, c) => acc + c.charCodeAt(0), 0);
  const minutesAgo = 5 + (seed % 55); // 5–59 min ago
  const statusIdx = seed % 3;
  const fakeLastSeen = new Date(Date.now() - minutesAgo * 60 * 1000).toISOString();
  return { status: DEMO_STATUS_BY_IDX[statusIdx], lastSeen: fakeLastSeen };
}

function getEngineerStatusText() {
  const name = settingsProfile?.name;
  return getPresenceForUser(name).status;
}

function getStatusColor(status) {
  return status === "online" ? "#23a55a" : status === "idle" ? "#f0b232" : status === "dnd" ? "#f23f43" : "#80848e";
}

function getStatusLabel(status) {
  return status === "dnd" ? "Do Not Disturb" : status === "offline" ? "Offline" : status === "invisible" ? "Invisible" : status === "idle" ? "Idle" : "Online";
}

function updateAutoPresenceStatus() {
  const now = new Date();
  const hour = now.getHours();
  // Working hours: 9 AM to 5 PM (9:00 - 17:00)
  const isWorkingHours = hour >= 9 && hour < 17;

  // Check if current user has any active tasks
  const hasActiveTasks = workingTaskIds.length > 0;

  const targetStatus = hasActiveTasks ? "dnd" : (isWorkingHours ? "online" : "idle");

  if (activeProfile === "manager") {
    if (managerPresenceStatus !== targetStatus) {
      managerPresenceStatus = targetStatus;
      localStorage.setItem("taskpilot:managerPresence", targetStatus);
    }
  } else {
    // If engineer is active, update last active timestamp
    localStorage.setItem("taskpilot:engineerLastActive", new Date().toISOString());
    if (engineerPresenceStatus !== targetStatus) {
      engineerPresenceStatus = targetStatus;
      localStorage.setItem("taskpilot:engineerPresence", targetStatus);
    }
  }
}

function startWorkingOnTask(id) {
  if (!workingTaskIds.includes(id)) workingTaskIds = [...workingTaskIds, id];
  setMyWorkingIds([...new Set([...getMyWorkingIds(), id])]);
  const task = state.prioritized.find(t => t.id === id);
  if (task && !taskTimeLogs[id]) {
    taskTimeLogs[id] = {
      title: task.canonicalTitle,
      severity: task.severity,
      source: task.sources?.join(" + ") || task.sourceId,
      startTime: new Date().toISOString(),
      endTime: null
    };
  }
  if (task) saveWorkingTask(getUserEmail(), getUserName(), id, task.canonicalTitle);
  if (task) pushCompanion("agent", `Started working on "${task.canonicalTitle}". I'll keep my eyes on your progress and help you fetch results!`, false);

  // Append system message to chat automatically: inform the manager
  const userDisplayName = settingsProfile.name || (activeProfile === "manager" ? "Manager" : "Engineer");
  if (task) {
    const startedChatMsg = {
      id: "msg-" + Date.now() + "-" + Math.random().toString(36).substr(2, 4),
      sender: "System",
      text: `[Agent] ${userDisplayName} started working on task ${task.id}: "${task.canonicalTitle}" (${task.severity})`,
      isSystem: true,
      timestamp: new Date().toISOString()
    };
    const currentChatMessages = JSON.parse(localStorage.getItem("taskpilot:chatMessages") || "[]");
    currentChatMessages.push(startedChatMsg);
    localStorage.setItem("taskpilot:chatMessages", JSON.stringify(currentChatMessages));
  }

  // Update status automatically
  updateAutoPresenceStatus();
}

function stopWorkingOnTask(id) {
  workingTaskIds = workingTaskIds.filter(x => x !== id);
  setMyWorkingIds(getMyWorkingIds().filter(x => x !== id));
  deleteWorkingTask(getUserEmail(), id);
  delete taskTimeLogs[id];

  // Append system message to chat automatically: inform the manager
  const task = state.prioritized.find(t => t.id === id);
  const userDisplayName = settingsProfile.name || (activeProfile === "manager" ? "Manager" : "Engineer");
  if (task) {
    const stoppedChatMsg = {
      id: "msg-" + Date.now() + "-" + Math.random().toString(36).substr(2, 4),
      sender: "System",
      text: `[Agent] ${userDisplayName} stopped/paused working on task ${task.id}: "${task.canonicalTitle}"`,
      isSystem: true,
      timestamp: new Date().toISOString()
    };
    const currentChatMessages = JSON.parse(localStorage.getItem("taskpilot:chatMessages") || "[]");
    currentChatMessages.push(stoppedChatMsg);
    localStorage.setItem("taskpilot:chatMessages", JSON.stringify(currentChatMessages));
  }

  // Update status automatically
  updateAutoPresenceStatus();
}

// ─── Rendering Layout ─────────────────────────────────────────────────────────
function render() {
  const focusedElementId = document.activeElement ? document.activeElement.id : null;
  let selectionStart = null;
  let selectionEnd = null;
  if (focusedElementId && document.activeElement instanceof HTMLInputElement) {
    selectionStart = document.activeElement.selectionStart;
    selectionEnd = document.activeElement.selectionEnd;
  }

  if (!authSession) {
    renderLogin();
    return;
  }

  // Update auto status on render
  updateAutoPresenceStatus();

  const currentDateStr = new Date().toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric", year: "numeric" }).toUpperCase();

  const queue = activeQueue();
  const selected = queue.find(t => t.id === selectedTaskId) || queue[0] || state.prioritized[0];
  const executionBrief = selected ? createExecutionBrief(selected) : null;
  const dynamicPlan = createDailyPlan(queue, calendarBlocks);
  currentContext = selected ? detectContext(selected) : null;
  // Push state updates to floating companion panel if in desktop shell
  if (window.taskPilotDesktop?.sendToFloating) {
    window.taskPilotDesktop.sendToFloating({
      type: "state-update",
      activeQueue: queue.map(t => ({
        id: t.id,
        title: t.canonicalTitle,
        severity: t.severity,
        score: t.score,
        body: t.body,
        due: t.due,
        sources: t.sources,
        sourceId: t.sourceId,
        eta: t.execution?.estimatedMinutes ? `~${t.execution.estimatedMinutes} min` : "~60 min"
      })),
      completedTaskIds: completedTaskIds,
      workingTaskIds: workingTaskIds,
      taskTimeLogs: taskTimeLogs,
      userName: settingsProfile.name,
      userRole: settingsProfile.role || "Full-stack Engineer"
    });
  }

  app.innerHTML = `
    <main class="shell ${isDesktopShell ? "desktop-shell" : ""} role-${activeProfile}">
      <aside class="sidebar ${sidebarCollapsed ? 'sidebar-collapsed' : ''}">

        <!-- Brand row: logo + title + toggle button inline -->
        <div class="sidebar-brand-row">
          <div class="brand-mark ${sidebarCollapsed ? 'brand-mark-expand' : ''}" id="${sidebarCollapsed ? 'sidebarExpandBtn' : ''}">
            <img src="${logoDataUrl}" alt="TaskPilot AI" style="width:100%;height:100%;object-fit:cover;border-radius:7px;display:block;">
          </div>
          <div class="sidebar-brand-text">
            <strong>TaskPilot AI</strong>
            <span>${getProfileLabel()}</span>
          </div>
          <button id="sidebarToggleBtn" class="sidebar-toggle-btn" title="Collapse sidebar">
            <svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2.2" viewBox="0 0 24 24">
              <circle cx="5" cy="12" r="1.2" fill="currentColor" stroke="none"/>
              <circle cx="12" cy="12" r="1.2" fill="currentColor" stroke="none"/>
              <circle cx="19" cy="12" r="1.2" fill="currentColor" stroke="none"/>
            </svg>
          </button>
        </div>

        <nav class="app-nav" aria-label="Workspace navigation">
          ${renderNavigation()}
        </nav>

         ${renderDiscordUserPanel()}
      </aside>


      <section class="workspace ${activeProfile === 'engineer' && ['overview', 'inbox'].includes(activePage) ? 'workspace-engineer-no-scroll' : ''}">
        ${activeProfile !== "manager" ? `
        <header class="topbar">
          <div>
            <h1>${navLabel(activePage)}</h1>
          </div>
          <div class="top-actions">
            ${activeProfile === "admin"
        ? `<button class="primary" id="executePipelineBtn">Execute Pipeline</button>
                 <button class="secondary ${adminErrorSimulated ? 'success' : 'danger'}" id="simulateErrorBtn">${adminErrorSimulated ? 'Clear LLM Error' : 'Simulate LLM Error'}</button>
                 <button class="secondary" id="resetAdminBtn">Reset System</button>`
        : activePage === 'calendar-ai'
          ? `<button class="primary" id="downloadCalendarBtn" style="display:flex;align-items:center;gap:8px;"><svg width="16" height="16" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>Download Calendar</button>`
          : activePage === 'agent-scan'
            ? `<button class="primary" id="runScan">Run autonomous scan</button>`
            : ''
      }
            <button class="secondary" id="logoutBtn" title="Sign Out & Switch Account" style="display:flex;align-items:center;gap:6px;padding:6px 12px;font-size:12.5px;font-weight:600;color:#475569;background:#fff;border:1px solid #ded5c8;border-radius:6px;cursor:pointer;">
              <svg width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1"/></svg>
              Sign Out
            </button>
          </div>
        </header>
        ` : ""}

        ${renderPageContent(selected, executionBrief, dynamicPlan)}
      </section>
    </main>

    ${renderCompanionDock()}
    ${renderCalendarPermissionModal()}
    ${renderAddJiraModal()}
    ${renderCalendarTaskModal()}
    ${renderFilePreviewModal()}
    ${renderTeammateTasksModal()}
    ${renderRecommendationsModal()}
    ${renderNvidiaCopilotSidebar()}
  `;

  bindEvents();

  // Auto-scroll admin console to bottom on update
  if (activeProfile === "admin") {
    // NVIDIA Copilot Sidebar Event Handlers
    document.querySelector("#closeNvidiaSidebarBtn")?.addEventListener("click", () => {
      activeNvidiaNodeId = null;
      render();
    });

    document.querySelector("#sidebarOptBtn")?.addEventListener("click", () => {
      const area = document.querySelector("#optStubArea");
      if (area) {
        area.style.display = area.style.display === "none" ? "block" : "none";
      }
    });

    document.querySelector("#deployNvidiaSidebarFixBtn")?.addEventListener("click", (e) => {
      const nodeId = e.currentTarget.dataset.nodeId;
      e.currentTarget.disabled = true;
      e.currentTarget.innerHTML = `<span style="display:inline-block;width:12px;height:12px;border:2px solid currentColor;border-top-color:transparent;border-radius:50%;animation:spin 0.7s linear infinite;margin-right:8px;"></span>Deploying Fix...`;

      if (nodeId === "alerts") {
        addAdminLog("nvidia", `[NVIDIA NIM] Analysis: Expired Slack Bot Token (Slack Webhook 403) detected.`);
        addAdminLog("nvidia", `[NVIDIA NIM] Applying Bearer authentication header hotfix to slack_agent.py.`);
        addAdminLog("nvidia", `[NVIDIA NIM] Re-verifying webhook response... HTTP 200 OK.`);
        addAdminLog("system", `[SYSTEM] Hotfix deployed successfully. Alerts node is restored to Healthy.`);

        setTimeout(() => {
          adminArchitectureNodes.alerts.status = "healthy";
          adminArchitectureNodes.alerts.error = null;
          adminArchitectureNodes.alerts.code = null;
          adminArchitectureNodes.alerts.fix = null;
          adminErrorSimulated = false; // clear simulated failure
          activeNvidiaNodeId = null;
          triggerLocalNotification("NVIDIA NIM Fix Deployed", "Slack webhook bot token updated successfully.");
          render();
        }, 1500);
      } else if (nodeId === "gemini") {
        addAdminLog("nvidia", `[NVIDIA NIM] Analysis: Gemini rate limits exceeded (HTTP 429).`);
        addAdminLog("nvidia", `[NVIDIA NIM] Applying circuit-breaker fallback decorator with Nemotron-70B.`);
        addAdminLog("nvidia", `[NVIDIA NIM] Re-verifying API response... HTTP 200 OK.`);
        addAdminLog("system", `[SYSTEM] Hotfix deployed successfully. Gemini node is restored to Healthy.`);

        setTimeout(() => {
          adminErrorSimulated = false;
          activeNvidiaNodeId = null;
          triggerLocalNotification("NVIDIA NIM Fix Deployed", "Gemini circuit-breaker fallback active.");
          render();
        }, 1500);
      } else if (nodeId === "router") {
        addAdminLog("nvidia", `[NVIDIA NIM] Analysis: Smart Router latency hotspot detected.`);
        addAdminLog("nvidia", `[NVIDIA NIM] Applying load-aware routing dispatcher to main.js.`);
        addAdminLog("nvidia", `[NVIDIA NIM] Re-verifying routing times... 95ms.`);
        addAdminLog("system", `[SYSTEM] Hotfix deployed successfully. Smart Router node is restored to Healthy.`);

        setTimeout(() => {
          adminErrorSimulated = false;
          activeNvidiaNodeId = null;
          triggerLocalNotification("NVIDIA NIM Fix Deployed", "Smart Router optimized load balancing active.");
          render();
        }, 1500);
      }
    });

    const logConsole = document.querySelector("#adminLogConsole");
    if (logConsole) {
      logConsole.scrollTop = logConsole.scrollHeight;
    }
  }

  if (focusedElementId) {
    const el = document.getElementById(focusedElementId);
    if (el) {
      el.focus();
      if (selectionStart !== null && selectionEnd !== null) {
        try {
          el.setSelectionRange(selectionStart, selectionEnd);
        } catch (e) { }
      }
    }
  }
}

