// ─── Boot ─────────────────────────────────────────────────────────────────────
// Safe render with error recovery — prevents blank page on runtime errors
function safeRender() {
  try {
    render();
  } catch (err) {
    console.error("[TaskPilot] render() threw:", err);
    // Show error overlay instead of blank page
    if (app) {
      app.innerHTML = `
        <main style="display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:100vh;background:#f7f4ee;font-family:Inter,system-ui,sans-serif;gap:16px;padding:40px;">
          <div style="display:flex;justify-content:center;margin-bottom:8px;color:#f59e0b;"><svg width="48" height="48" fill="none" stroke="currentColor" stroke-width="1.5" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"/></svg></div>
          <h2 style="margin:0;color:#152238;font-family:Outfit,sans-serif;">TaskPilot ran into a problem</h2>
          <p style="margin:0;color:#4a5568;max-width:480px;text-align:center;">${escapeHtml ? escapeHtml(err.message) : err.message}</p>
          <button onclick="localStorage.removeItem('taskpilot:session');location.reload();"
            style="padding:12px 24px;background:#152238;color:#fff;border:none;border-radius:10px;font-weight:700;cursor:pointer;font-size:14px;">
            Clear session &amp; reload
          </button>
        </main>`;
    }
  }
}

// ─── Browser OAuth callback handler ──────────────────────────────────────────
// Supabase redirects back with #access_token=...&token_type=bearer in the URL hash
async function handleOAuthCallback() {
  if (isDesktopShell) return; // Electron handles auth via IPC — skip
  const hash = window.location.hash;
  if (!hash.includes("access_token=")) return;


  const params = new URLSearchParams(hash.slice(1));
  const accessToken = params.get("access_token");
  if (!accessToken) return;

  // Clear the hash from the URL so it doesn't persist on refresh
  window.history.replaceState(null, "", window.location.pathname);

  try {
    let userEmail = "";
    let userName = "";
    let userId = "";
    let avatarUrl = "";

    try {
      const base64Url = accessToken.split(".")[1];
      const base64 = base64Url.replace(/-/g, "+").replace(/_/g, "/");
      const jsonPayload = decodeURIComponent(atob(base64).split("").map(c => "%" + ("00" + c.charCodeAt(0).toString(16)).slice(-2)).join(""));
      const payload = JSON.parse(jsonPayload);
      userId = payload.sub || payload.id || `user-${Date.now()}`;
      userEmail = payload.email || "user@taskpilot.dev";
      userName = payload.user_metadata?.full_name || payload.user_metadata?.name || payload.name || userEmail.split("@")[0];
      avatarUrl = payload.user_metadata?.avatar_url || payload.picture || "";
    } catch (jwtErr) {
      console.warn("[TaskPilot] JWT decoding failed, attempting API fallback:", jwtErr.message);
    }

    if (!userEmail) {
      const SUPABASE_URL = backendConfig?.supabaseUrl || "https://pzovknqrllnifvsrjvts.supabase.co";
      const res = await fetch(`${SUPABASE_URL}/auth/v1/user`, {
        headers: { "Authorization": `Bearer ${accessToken}` }
      });
      if (res.ok) {
        const user = await res.json();
        userId = user.id;
        userEmail = user.email;
        userName = user.user_metadata?.full_name || user.user_metadata?.name || user.email;
        avatarUrl = user.user_metadata?.avatar_url || "";
      }
    }

    if (!userEmail) {
      userEmail = "google-user@taskpilot.dev";
      userName = "Google User";
      userId = `google-${Date.now()}`;
    }

    const pendingRole = localStorage.getItem("taskpilot:pending-role") || "engineer";
    localStorage.removeItem("taskpilot:pending-role");

    authSession = {
      provider: "google-supabase",
      role: pendingRole,
      userId: userId,
      email: userEmail,
      name: userName,
      avatarUrl: avatarUrl
    };
    activeProfile = pendingRole;
    localStorage.setItem("taskpilot:session", JSON.stringify(authSession));

    logUserLogin(authSession.email, authSession.name, authSession.role);
    syncSettingsProfileWithSession();
    completedTaskIds = getMyCompletedIds();
    workingTaskIds = getMyWorkingIds();
  } catch (err) {
    console.error("[TaskPilot] OAuth callback failed:", err.message);
    authError = "Google sign-in failed. Error: " + err.message;
  }
}

// Validate session before boot — clear malformed sessions
try {
  const rawSession = localStorage.getItem("taskpilot:session");
  if (rawSession) {
    const parsed = JSON.parse(rawSession);
    if (!parsed || !parsed.provider || !parsed.role) {
      localStorage.removeItem("taskpilot:session");
      authSession = null;
    }
  }
} catch {
  localStorage.removeItem("taskpilot:session");
  authSession = null;
}

// Render immediately so the page isn't blank while backend connects
safeRender();
// Then load backend config/state and re-render with live data
loadBackendConfig().finally(async () => {
  // Restore per-user completion state from localStorage
  completedTaskIds = getMyCompletedIds();
  workingTaskIds = getMyWorkingIds();

  // Rebuild today queue with real user name (not role label)
  const engineerName = activeProfile === "manager" ? "Manager" : (settingsProfile?.name || null);
  todayQueue = buildTodayCapacityQueue(state.prioritized, engineerName, taskTimeLogs);
  depGraph = buildDependencyGraph(state.prioritized);
  safeRender();

  // Start presence heartbeat — push status to backend every 5s
  startPresenceHeartbeat();

  // Sync completions from Supabase (background, then re-render)
  syncCompletionsFromSupabase().then(() => {
    safeRender();
    startRealTimeSync(); // live updates
  });

  // Async: re-score today queue with Gemini for smarter ranking
  geminiRescoreTodayQueue();
});

// ─── Gemini Re-score Today Queue ─────────────────────────────────────────────
async function geminiRescoreTodayQueue() {
  if (todayQueueGeminiScored || todayQueue.length === 0) return;
  try {
    const slim = todayQueue.map(t => ({
      id: t.id,
      title: t.canonicalTitle,
      severity: t.severity,
      due: t.due,
      impact: t.impact,
      dependencies: t.dependencies,
      sources: t.sources,
      owner: t.owner,
      isBlocking: t.isBlocking,
      blocksCount: t.blocksCount || 0
    }));
    const rescored = await geminPrioritizeTasks(slim);
    if (!Array.isArray(rescored) || rescored.length === 0) return;

    // Merge Gemini scores back into todayQueue
    const scoreMap = {};
    rescored.forEach(r => { if (r.id) scoreMap[r.id] = r; });
    todayQueue = todayQueue.map(t => {
      const g = scoreMap[t.id];
      if (!g) return t;
      return {
        ...t,
        score: g.score || t.score,
        rankReasons: Array.isArray(g.rankReasons) && g.rankReasons.length > 0
          ? g.rankReasons
          : t.rankReasons
      };
    }).sort((a, b) => b.score - a.score);

    todayQueueGeminiScored = true;
    safeRender();
    console.log("[TaskPilot] Today queue re-scored by Gemini ✅");
  } catch (err) {
    console.warn("[TaskPilot] Gemini re-score skipped:", err.message);
  }
}

    